import{_ as t,o as i,c as o,aj as a}from"./chunks/framework.Co0EVkx3.js";const h=JSON.parse('{"title":"AnvilLib Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"en/posts/docs/anvillib/index.md","filePath":"en/posts/docs/anvillib/index.md","lastUpdated":1773837867000}'),n={name:"en/posts/docs/anvillib/index.md"};function r(d,e,l,s,c,g){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="anvillib-documentation" tabindex="-1">AnvilLib Documentation <a class="header-anchor" href="#anvillib-documentation" aria-label="Permalink to “AnvilLib Documentation”">​</a></h1><p><strong>AnvilLib</strong> is a NeoForge mod library developed by <a href="https://github.com/Anvil-Dev" target="_blank" rel="noreferrer">Anvil Dev</a>, providing Minecraft (1.21.1) mod developers with a collection of practical tools and frameworks.</p><h2 id="module-overview" tabindex="-1">Module Overview <a class="header-anchor" href="#module-overview" aria-label="Permalink to “Module Overview”">​</a></h2><p>AnvilLib uses a modular design. Each module can be included independently, or you can use the aggregate artifact to get all features at once.</p><table tabindex="0"><thead><tr><th>Module</th><th>Maven Artifact (prefix <code>dev.anvilcraft.lib:</code>)</th><th>Description</th></tr></thead><tbody><tr><td><strong>Config</strong></td><td><code>anvillib-config-neoforge-1.21.1</code></td><td>Annotation-based configuration system</td></tr><tr><td><strong>Integration</strong></td><td><code>anvillib-integration-neoforge-1.21.1</code></td><td>Mod compatibility integration framework</td></tr><tr><td><strong>Network</strong></td><td><code>anvillib-network-neoforge-1.21.1</code></td><td>Networking with automatic packet registration</td></tr><tr><td><strong>Recipe</strong></td><td><code>anvillib-recipe-neoforge-1.21.1</code></td><td>In-world recipe system</td></tr><tr><td><strong>Moveable Entity Block</strong></td><td><code>anvillib-moveable-entity-block-neoforge-1.21.1</code></td><td>Support for piston-movable block entities</td></tr><tr><td><strong>Registrum</strong></td><td><code>anvillib-registrum-neoforge-1.21.1</code></td><td>Simplified registration system (based on Registrate)</td></tr><tr><td><strong>Main (Aggregate)</strong></td><td><code>anvillib-neoforge-1.21.1</code></td><td>Aggregate artifact bundling all submodules</td></tr></tbody></table><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h2><ul><li>Java 21+</li><li>Minecraft 1.21.1</li><li>NeoForge 21.1.x</li></ul><h2 id="documentation-navigation" tabindex="-1">Documentation Navigation <a class="header-anchor" href="#documentation-navigation" aria-label="Permalink to “Documentation Navigation”">​</a></h2><ol><li><a href="./01_getting_started.html">Getting Started (Dependency Setup)</a></li><li><a href="./02_config.html">Config Module</a></li><li><a href="./03_integration.html">Integration Module</a></li><li><a href="./04_network.html">Network Module</a></li><li><a href="./05_recipe.html">Recipe (In-World Recipe) Module</a></li><li><a href="./06_moveable_entity_block.html">Moveable Entity Block Module</a></li><li><a href="./07_registrum.html">Registrum Module</a></li></ol>',9)])])}const u=t(n,[["render",r]]);export{h as __pageData,u as default};
